import React, { useState } from 'react';
import axios from 'axios';

const AdminUpload = () => {
    const [title, setTitle] = useState('');
    const [artist, setArtist] = useState('');
    const [songFile, setSongFile] = useState(null);
    const [imageFile, setImageFile] = useState(null);

    const handleUpload = async (e) => {
        e.preventDefault();
        
        // Lấy thông tin user từ localStorage
        const user = JSON.parse(localStorage.getItem('user'));
        if (!user) return alert("Vui lòng đăng nhập!");

        const formData = new FormData();
        formData.append('title', title);
        formData.append('artist', artist);
        formData.append('userId', user._id); // Gửi ID
        formData.append('uploaderName', user.username); // Gửi tên người đăng
        formData.append('songFile', songFile); // Key phải khớp với Backend
        formData.append('imageFile', imageFile);

        try {
            await axios.post('http://localhost:5000/api/songs', formData, {
                headers: { 'Content-Type': 'multipart/form-data' }
            });
            alert("Tải lên thành công!");
            window.location.href = '/';
        } catch (err) {
            console.error(err);
            alert("Lỗi khi tải lên: " + (err.response?.data?.message || err.message));
        }
    };

    return (
        <div style={{ padding: '50px', maxWidth: '500px', margin: '0 auto' }}>
            <form onSubmit={handleUpload} style={{ display: 'flex', flexDirection: 'column', gap: '15px' }}>
                <h2>ĐĂNG NHẠC MỚI</h2>
                <input type="text" placeholder="Tên bài hát" onChange={(e)=>setTitle(e.target.value)} required />
                <input type="text" placeholder="Ca sĩ/Nghệ sĩ" onChange={(e)=>setArtist(e.target.value)} required />
                <label>File nhạc (MP3):</label>
                <input type="file" accept="audio/*" onChange={(e)=>setSongFile(e.target.files[0])} required />
                <label>Ảnh bìa (JPG/PNG):</label>
                <input type="file" accept="image/*" onChange={(e)=>setImageFile(e.target.files[0])} required />
                <button type="submit" style={{ padding: '10px', background: '#1db954', color: 'white', border: 'none', borderRadius: '5px', fontWeight: 'bold' }}>TẢI LÊN</button>
            </form>
        </div>
    );
};

export default AdminUpload;
